import React, { useState, useEffect } from 'react';
import './App.css';

/**
 * Parses characters.txt into an array of columns.
 * Each block separated by a blank line becomes one column.
 * The first non-empty line is the column name; the rest are entries.
 */
function parseCharactersTxt(text) {
  const blocks = text.trim().split(/\n[ \t]*\n/);
  return blocks
    .map(block => {
      const lines = block.split('\n').map(l => l.trim()).filter(Boolean);
      if (lines.length < 1) return null;
      const [name, ...entries] = lines;
      return { name, entries };
    })
    .filter(Boolean);
}

/**
 * Fetches a fanart-like image from Wikimedia Commons.
 * The query includes both column and row data for better relevance.
 */
async function fetchFanartImage(columnName, entry) {
  const query = `${entry} ${columnName} fanart`;
  try {
    const params = new URLSearchParams({
      action: 'query',
      generator: 'search',
      gsrsearch: query,
      gsrnamespace: '6',
      gsrlimit: '8',
      prop: 'imageinfo',
      iiprop: 'url',
      iiurlwidth: '320',
      format: 'json',
      origin: '*',
    });

    const res = await fetch(`https://commons.wikimedia.org/w/api.php?${params}`);
    if (!res.ok) return null;
    const data = await res.json();
    const pages = data.query?.pages;
    if (!pages) return null;
    const sorted = Object.values(pages).sort(
      (a, b) => (a.index ?? Infinity) - (b.index ?? Infinity)
    );
    for (const page of sorted) {
      const imageInfo = page.imageinfo?.[0];
      if (imageInfo?.thumburl) return imageInfo.thumburl;
      if (imageInfo?.url) return imageInfo.url;
    }
    return null;
  } catch {
    return null;
  }
}

/** A single data cell that fetches and toggles its image on click. */
function CharacterCell({ columnName, entry }) {
  // undefined = not yet fetched, null = fetched but no result, string = image URL
  const [image, setImage] = useState(undefined);
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const query = `${columnName} ${entry}`;

  const handleClick = async () => {
    const next = !open;
    setOpen(next);
    if (next && image === undefined) {
      setLoading(true);
      const img = await fetchFanartImage(columnName, entry);
      setImage(img);
      setLoading(false);
    }
  };

  return (
    <td
      className={`char-cell${open ? ' open' : ''}`}
      onClick={handleClick}
      title={open ? 'Click to collapse' : 'Click to reveal image'}
    >
      <span className="char-name">{entry}</span>
      {open && (
        <div className="char-image">
          {loading ? (
            <div className="loading-text">Loading…</div>
          ) : image ? (
            <img src={image} alt={`${columnName} - ${entry}`} />
          ) : (
            <div className="no-image">No image found</div>
          )}
        </div>
      )}
    </td>
  );
}

export default function App() {
  const [activeTab, setActiveTab] = useState('gallery');
  const [columns, setColumns] = useState([]);
  const [rawText, setRawText] = useState('');
  const [editorText, setEditorText] = useState('');
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saveStatus, setSaveStatus] = useState('idle');

  const loadCharacters = () => {
    setLoading(true);
    setError(null);

    return fetch('/api/characters')
      .then(res => {
        if (!res.ok) throw new Error(`Could not load characters.txt (${res.status})`);
        return res.text();
      })
      .then(text => {
        setRawText(text);
        setEditorText(text);
        setColumns(parseCharactersTxt(text));
        setLoading(false);
      })
      .catch(e => {
        setError(e.message);
        setLoading(false);
      });
  };

  useEffect(() => {
    loadCharacters();
  }, []);

  const handleSave = async () => {
    setSaveStatus('saving');
    try {
      const res = await fetch('/api/characters', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: editorText }),
      });

      if (!res.ok) {
        throw new Error(`Save failed (${res.status})`);
      }

      setRawText(editorText);
      setColumns(parseCharactersTxt(editorText));
      setSaveStatus('saved');
      setTimeout(() => setSaveStatus('idle'), 1200);
    } catch {
      setSaveStatus('error');
    }
  };

  const hasUnsavedChanges = editorText !== rawText;

  if (loading) return <div className="status">Loading…</div>;
  if (error)   return <div className="status error">{error}</div>;

  const maxRows = Math.max(...columns.map(c => c.entries.length), 0);

  return (
    <div className="app">
      <h1>Character Gallery</h1>
      <p className="hint">Fanart lookup uses both category and character name</p>

      <div className="tabs">
        <button
          type="button"
          className={`tab-btn${activeTab === 'gallery' ? ' active' : ''}`}
          onClick={() => setActiveTab('gallery')}
        >
          Gallery
        </button>
        <button
          type="button"
          className={`tab-btn${activeTab === 'editor' ? ' active' : ''}`}
          onClick={() => setActiveTab('editor')}
        >
          Edit chars.txt
        </button>
      </div>

      {activeTab === 'gallery' ? (
        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                {columns.map(col => (
                  <th key={col.name}>{col.name}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {Array.from({ length: maxRows }, (_, i) => (
                <tr key={i}>
                  {columns.map(col =>
                    col.entries[i] ? (
                      <CharacterCell
                        key={col.name}
                        columnName={col.name}
                        entry={col.entries[i]}
                      />
                    ) : (
                      <td key={col.name} className="empty-cell" />
                    )
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="editor-panel">
          <textarea
            value={editorText}
            onChange={e => setEditorText(e.target.value)}
            spellCheck={false}
            aria-label="Edit characters text"
          />
          <div className="editor-actions">
            <button type="button" onClick={handleSave} disabled={!hasUnsavedChanges || saveStatus === 'saving'}>
              {saveStatus === 'saving' ? 'Saving...' : 'Save chars.txt'}
            </button>
            <button type="button" onClick={loadCharacters}>
              Reload from disk
            </button>
            {saveStatus === 'saved' && <span className="save-ok">Saved.</span>}
            {saveStatus === 'error' && <span className="save-error">Save failed.</span>}
          </div>
        </div>
      )}
    </div>
  );
}
